});
```

5. Run your tests:
   a. Start your Docker container if it's not already running.
   b. Run your Cypress tests:

```bash
cypress open
```

This setup allows you to run your tests in a Docker environment, and it captures and saves screenshots when tests fail. The screenshots will be saved in the `cypress/screenshots` folder.

Here's a C++ function that converts Markdown formatted text to HTML using the `rapidjson` library for parsing and `fmt` library for formatting strings:

```cpp
#include <iostream>
#include <string>
#include <rapidjson/document.h>
#include <fmt/format.h>
#include <fmt/ranges.h>

std::string markdownToHtml(std::string& markdownText) {
    // Initialize the output string
    std::string htmlText;

    // Parse the markdown text using rapidjson
    rapidjson::Document document;
    document.Parse<0>(markdownText.c_str()).AssertSuccess();

    // Iterate through the parsed document and generate HTML
    for (auto& it : document) {
        if (it.IsObject()) {
            // Handle object (e.g. paragraph, list, header)
            switch (it["type"].GetString()) {
                case "paragraph":
                    htmlText += "<p>";
                    for (auto& innerIt : it) {
                        if (innerIt.IsString()) {
                            htmlText += fmt::format("<{}>{}{}</>", innerIt.GetString(), innerIt["value"].GetString(), "</>");
                        }
                    }
                    htmlText += "</p>";
                    break;
                case "header":
                    htmlText += fmt::format("<h{}>{}{}</h{}>", it["level"].GetInt(), it["value"].GetString(), "</>", it["level"].GetInt());
                    break;
                case "list":
                    htmlText += "<ul>";
                    for (auto& listItem : it["items"]) {
                        htmlText += "<li>";
                        for (auto& innerListItem : listItem) {
                            if (innerListItem.IsString()) {
                                htmlText += fmt::format("<{}>{}{}</>", innerListItem.GetString(), innerListItem["value"].GetString(), "</>");
                            }
                        }
                        htmlText += "</li>";
                    }
                    htmlText += "</ul>";
                    break;
                default:
                    break;
            }
        } else if (it.IsArray()) {
            // Handle array (e.g. code block)
            htmlText += "<pre><code>";
            for (auto& innerIt : it) {
                if (innerIt.IsString()) {
                    htmlText += fmt::format("{}\n", innerIt["value"].GetString());
                }
            }
            htmlText += "</code></pre>";
        } else if (it.IsString()) {
            // Handle inline elements (e.g. links, images)
            switch (it["type"].GetString()) {
                case "link":
                    htmlText += fmt::format("<a href=\"{}\">{}</a>", it["url"].GetString(), it["value"].GetString());
                    break;
                case "image":
                    htmlText += fmt::format("<img src=\"{}\" alt=\"{}\">", it["url"].GetString(), it["value"].GetString());
                    break;
                default:
                    htmlText += it["value"].GetString();
                    break;
            }
        }
    }

    return htmlText;
}

int main() {
    std::string markdownText = "# Header\n\nParagraph\n\n- List item 1\n- List item 2\n\n[Link](https://example.com)\n![Image](https://example.com/image.png)";
    std::string htmlText = markdownToHtml(markdownText);
    std::cout << htmlText << std::endl;
    return 0;
}
```

This function uses the `rapidjson` library to parse the Markdown text and iterate through the parsed document. It generates HTML based on the parsed elements, such as paragraphs, headers, lists, code blocks, links, and images.

Note: This function is a basic implementation and does not cover all Markdown syntax. You can extend it to support more Markdown elements as needed.

