Here's a function written in JavaScript that takes an array of 5 numbers as input and checks if any of them is a prime number. If a prime number is found, it will be printed to the console.

```javascript
function checkPrimes(numbers) {
  if (numbers.length !== 5) {
    console.log("Invalid input, please provide an array of 5 numbers.");
    return;
  }

  for (let number of numbers) {
    if (isPrime(number)) {
      console.log(`The prime number found in the array is: ${number}`);
      return;
    }
  }

  console.log("No prime numbers found in the given array.");
}

function isPrime(num) {
  if (num <= 1) return false;
  if (num === 2 || num === 3) return true;
  if (num % 2 === 0 || num % 3 === 0) return false;

  for (let i = 5; i * i <= num; i += 6) {
    if (num % i === 0 || num % (i + 2) === 0) return false;
  }

  return num % 4 !== 0;
}

// Example usage:
let numbers = [4, 6, 10, 13, 19];
checkPrimes(numbers);
```

