```gd
extends KinematicBody

var speed = 10
var jump_height = 10
var jump_power = 300
var is_jumping = false
var is_moving = false

func _physics_process(delta):
    if Input.is_action_pressed("ui_left"):
        rotate_local(Vector2(-speed * delta, 0))
        is_moving = true
    elif Input.is_action_pressed("ui_right"):
        rotate_local(Vector2(speed * delta, 0))
        is_moving = true
    else:
        is_moving = false

    if Input.is_action_just_pressed("ui_jump") and not is_jumping:
        is_jumping = true
        jump(Vector2(0, jump_power))

func _on_AnimationTimer_timeout():
    if is_jumping:
        is_jumping = false

func _on_AnimationTimer_start():
    if is_jumping:
        jump_height = 0

func _on_AnimationTimer_stop():
    if is_jumping:
        jump_height = jump_height - 1
        if jump_height <= 0:
            jump_height = 0
            is_jumping = false
```

